class DependencyLockManager:
    """Manages Python dependency lock files with security best practices."""
    
    ALLOWED_HASH_ALGORITHMS = {'sha256', 'sha384', 'sha512'}
    ALLOWED_INDEX_URLS = {
        'https://pypi.org/simple',
        'https://pypi.python.org/simple'
    }
    
    def __init__(self, project_root: str = '.'):
        self.project_root = Path(project_root).resolve()
        self.requirements_file = self.project_root / 'requirements.txt'
        self.requirements_in = self.project_root / 'requirements.in'
        self.pyproject_file = self.project_root / 'pyproject.toml'
        self.poetry_lock = self.project_root / 'poetry.lock'
        
    def validate_package_name(self, package_name: str) -> bool:
        """Validate package name against PEP 508 naming conventions."""
        pattern = r'^[a-zA-Z0-9]([a-zA-Z0-9._-]*[a-zA-Z0-9])?$'
        if not re.match(pattern, package_name):
            return False
        if len(package_name) > 214:
            return False
        return True
    
    def validate_version_specifier(self, version_spec: str) -> bool:
        """Validate version specifier format."""
        pattern = r'^([<>=!~]+)?[\d\w\.\*\+]+([,\s]*([<>=!~]+)?[\d\w\.\*\+]+)*$'
        return bool(re.match(pattern, version_spec.strip()))
    
    def validate_index_url(self, url: str) -> bool:
        """Validate package index URL is from allowed sources."""
        parsed = urlparse(url)
        if parsed.scheme not in ('https',):
            return False
        normalized_url = f"{parsed.scheme}://{parsed.netloc}{parsed.path}".rstrip('/')
        return normalized_url in self.ALLOWED_INDEX_URLS
    
    def validate_hash(self, hash_string: str) -> bool:
        """Validate hash format and algorithm."""
        if ':' not in hash_string:
            return False
        algorithm, hash_value = hash_string.split(':', 1)
        if algorithm not in self.ALLOWED_HASH_ALGORITHMS:
            return False
        expected_length = {
            'sha256': 64,
            'sha384': 96,
            'sha512': 128
        }
        if len(hash_value) != expected_length.get(algorithm, 0):
            return False
        if not re.match(r'^[a-fA-F0-9]+$', hash_value):
            return False
        return True
    
    def generate_requirements_with_hashes(self, 
                                         input_file: Optional[str] = None,
                                         output_file: Optional[str] = None,
                                         python_version: Optional[str] = None) -> bool:
        """Generate requirements.txt with package hashes using pip-compile."""
        input_path = Path(input_file) if input_file else self.requirements_in
        output_path = Path(output_file) if output_file else self.requirements_file
        
        if not input_path.exists():
            print(f"Error: Input file {input_path} does not exist", file=sys.stderr)
            return False
        
        with open(input_path, 'r') as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                if line.startswith('-'):
                    continue
                parts = re.split(r'[<>=!~]', line, 1)
                package_name = parts[0].strip()
                if not self.validate_package_name(package_name):
                    print(f"Error: Invalid package name: {package_name}", file=sys.stderr)
                    return False
        
        cmd = [
            sys.executable, '-m', 'piptools', 'compile',
            '--generate-hashes',
            '--allow-unsafe',
            '--resolver=backtracking',
            '--output-file', str(output_path),
            str(input_path)
        ]
        
        if python_version:
            if not re.match(r'^\d+\.\d+$', python_version):
                print(f"Error: Invalid Python version format: {python_version}", file=sys.stderr)
                return False
            cmd.extend(['--python-version', python_version])
        
        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=300,
                check=False
            )
            
            if result.returncode != 0:
                print(f"Error generating requirements: {result.stderr}", file=sys.stderr)
                return False
            
            if not self.verify_requirements_file(output_path):
                print("Error: Generated requirements file failed validation", file=sys.stderr)
                if output_path.exists():
                    output_path.unlink()
                return False
            
            print(f"Successfully generated {output_path} with hashes")
            return True
            
        except subprocess.TimeoutExpired:
            print("Error: pip-compile timed out", file=sys.stderr)
            return False
        except FileNotFoundError:
            print("Error: pip-tools not installed. Install with: pip install pip-tools", file=sys.stderr)
            return False
        except Exception as e:
            print(f"Error: {str(e)}", file=sys.stderr)
            return False
    
    def verify_requirements_file(self, requirements_file: Optional[Path] = None) -> bool:
        """Verify requirements.txt has valid hashes for all packages."""
        req_file = requirements_file or self.requirements_file
        
        if not req_file.exists():
            print(f"Error: {req_file} does not exist", file=sys.stderr)
            return False
        
        packages_without_hashes = []
        invalid_hashes = []
        invalid_packages = []
        
        with open(req_file, 'r') as f:
            current_package = None
            has_hash = False
            
            for line_num, line in enumerate(f, 1):
                line = line.strip()
                
                if not line or line.startswith('#'):
                    continue
                
                if line.startswith('--hash='):
                    hash_value = line[7:]
                    if not self.validate_hash(hash_value):
                        invalid_hashes.append((line_num, hash_value))
                    has_hash = True
                    continue
                
                if line.startswith('-'):
                    continue
                
                if current_package and not has_hash:
                    packages_without_hashes.append(current_package)
                
                match = re.match(r'^([a-zA-Z0-9._-]+)', line)
                if match:
                    package_name = match.group(1)
                    if not self.validate_package_name(package_name):
                        invalid_packages.append((line_num, package_name))
                    current_package = package_name
                    has_hash = False
            
            if current_package and not has_hash:
                packages_without_hashes.append(current_package)
        
        if invalid_packages:
            print("Invalid package names found:", file=sys.stderr)
            for line_num, pkg in invalid_packages:
                print(f"  Line {line_num}: {pkg}", file=sys.stderr)
        
        if packages_without_hashes:
            print("Packages without hashes found:", file=sys.stderr)
            for pkg in packages_without_hashes:
                print(f"  {pkg}", file=sys.stderr)
        
        if invalid_hashes:
            print("Invalid hash formats found:", file=sys.stderr)
            for line_num, hash_val in invalid_hashes:
                print(f"  Line {line_num}: {hash_val}", file=sys.stderr)
        
        return not (packages_without_hashes or invalid_hashes or invalid_packages)
    
    def sync_dependencies(self, requirements_file: Optional[str] = None) -> bool:
        """Install dependencies from locked requirements file."""
        req_file = Path(requirements_file) if requirements_file else self.requirements_file
        
        if not req_file.exists():
            print(f"Error: {req_file} does not exist", file=sys.stderr)
            return False
        
        if not self.verify_requirements_file(req_file):
            print("Error: Requirements file validation failed", file=sys.stderr)
            return False
        
        cmd = [
            sys.executable, '-m', 'pip', 'install',
            '--require-hashes',
            '--no-deps',
            '-r', str(req_file)
        ]
        
        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=600,
                check=False
            )
            
            if result.returncode != 0:
                print(f"Error installing dependencies: {result.stderr}", file=sys.stderr)
                return False
            
            print(f"Successfully installed dependencies from {req_file}")
            return True
            
        except subprocess.TimeoutExpired:
            print("Error: pip install timed out", file=sys.stderr)
            return False
        except Exception as e:
            print(f"Error: {str(e)}", file=sys.stderr)
            return False
    
    def update_dependency(self, package_name: str, 
                         version: Optional[str] = None) -> bool:
        """Update a specific dependency in requirements.in."""
        if not self.validate_package_name(package_name):
            print(f"Error: Invalid package name: {package_name}", file=sys.stderr)
            return False
        
        if version and not self.validate_version_specifier(version):
            print(f"Error: Invalid version specifier: {version}", file=sys.stderr)
            return False
        
        if not self.requirements_in.exists():
            print(f"Error: {self.requirements_in} does not exist", file=sys.stderr)
            return False
        
        with open(self.requirements_in, 'r') as f:
            lines = f.readlines()
        
        updated = False
        new_lines = []
        
        for line in lines:
            stripped = line.strip()
            if stripped and not stripped.startswith('#'):
                match = re.match(r'^([a-zA-Z0-9._-]+)', stripped)
                if match and match.group(1) == package_name:
                    if version:
                        new_lines.append(f"{package_name}{version}\n")
                    else:
                        new_lines.append(f"{package_name}\n")
                    updated = True
                    continue
            new_lines.append(line)
        
        if not updated:
            if version:
                new_lines.append(f"{package_name}{version}\n")
            else:
                new_lines.append(f"{package_name}\n")
        
        with open(self.requirements_in, 'w') as f:
            f.writelines(new_lines)
        
        print(f"Updated {package_name} in {self.requirements_in}")
        return self.generate_requirements_with_hashes()
    
    def poetry_lock_update(self, package_name: Optional[str] = None) -> bool:
        """Update Poetry lock file."""
        if not self.pyproject_file.exists():
            print(f"Error: {self.pyproject_file} does not exist", file=sys.stderr)
