    def verify_poetry_lock(self) -> bool:
        """Verify Poetry lock file integrity."""
        if not self.poetry_lock.exists():
            print(f"Error: {self.poetry_lock} does not exist", file=sys.stderr)
            return False
        
        try:
            with open(self.poetry_lock, 'r') as f:
                content = f.read()
            
            if 'package' not in content:
                print("Error: Invalid poetry.lock format", file=sys.stderr)
                return False
            
            cmd = ['poetry', 'lock', '--check']
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=60,
                check=False,
                cwd=str(self.project_root)
            )
            
            if result.returncode != 0:
                print(f"Poetry lock check failed: {result.stderr}", file=sys.stderr)
                return False
            
            return True
            
        except Exception as e:
            print(f"Error verifying poetry.lock: {str(e)}", file=sys.stderr)
            return False
    
    def export_from_poetry(self, output_file: Optional[str] = None) -> bool:
        """Export Poetry dependencies to requirements.txt format."""
        output_path = Path(output_file) if output_file else self.requirements_file
        
